import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  Button, Dialog, DialogActions, DialogContent, DialogTitle,
  TextField, Typography, Box,
} from '@mui/material';
import ZoomInIcon from '@mui/icons-material/ZoomIn';
import ZoomOutIcon from '@mui/icons-material/ZoomOut';
import CenterFocusStrongIcon from '@mui/icons-material/CenterFocusStrong';
import axios from 'axios';
import * as d3 from 'd3';

function AdamToMuhammad({ user }) {
  const svgRef = useRef(null);
  const containerRef = useRef(null);
  const zoomRef = useRef(null);

  const [chain, setChain] = useState([]);              // all data from API
  const [filteredChain, setFilteredChain] = useState([]); // filtered data for display
  const [loading, setLoading] = useState(true);
  const [zoom, setZoom] = useState(1);

  // filter state
  const [startGen, setStartGen] = useState('');   // user enters starting generation number

  const [open, setOpen] = useState(false);
  const [editOpen, setEditOpen] = useState(false);
  const [editingNode, setEditingNode] = useState(null);
  const [editData, setEditData] = useState({ name: '', generation_number: '', info: '', parent_id: '' });
  const [newData, setNewData] = useState({ name: '', generation_number: '', info: '', parent_id: '' });

  const token = localStorage.getItem('token');
  const isAdmin = user && user.role === 'admin';

  // ─── Load ALL data from API ───
  const loadChain = useCallback(async () => {
    try {
      const res = await axios.get('/api/prophets');
      setChain(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadChain(); }, [loadChain]);

  // ─── Filter data whenever chain or startGen changes ───
  useEffect(() => {
    if (!startGen || startGen === '') {
      // no filter → show all
      setFilteredChain(chain);
      return;
    }
    const gen = parseInt(startGen);
    if (isNaN(gen)) {
      setFilteredChain([]);
      return;
    }
    // filter nodes with generation_number >= gen
    const filtered = chain.filter(n => n.generation_number >= gen);
    // if none, show all? or empty. We'll show empty.
    setFilteredChain(filtered);
  }, [chain, startGen]);

  // Helper: father name for "bin" line
  const getFatherName = useCallback((node) => {
    if (!node?.parent_id) return null;
    const father = chain.find(n => n.id === node.parent_id);
    return father ? father.name : null;
  }, [chain]);

  // ─── Admin handlers ───
  const handleAddAfter = useCallback((node) => {
    setNewData({
      name: '',
      generation_number: node.generation_number + 1,
      info: '',
      parent_id: node.id,
    });
    setOpen(true);
  }, []);

  const handleEdit = useCallback((node) => {
    setEditingNode(node);
    setEditData({
      name: node.name,
      generation_number: node.generation_number,
      info: node.info || '',
      parent_id: node.parent_id || '',
    });
    setEditOpen(true);
  }, []);

  const handleDelete = useCallback(async (node) => {
    if (!window.confirm(`Delete ${node.name}?`)) return;
    try {
      await axios.delete(`/api/prophets/${node.id}`, { headers: { 'x-auth-token': token } });
      loadChain();
    } catch (err) { alert('Delete failed'); }
  }, [token, loadChain]);

  const handleAddSubmit = async () => {
    if (!newData.name.trim() || !newData.generation_number) {
      alert('Name and Generation Number are required');
      return;
    }
    try {
      await axios.post('/api/prophets', newData, { headers: { 'x-auth-token': token } });
      setOpen(false);
      loadChain();
    } catch (err) { alert(err.response?.data?.msg || 'Add failed'); }
  };

  const handleEditSubmit = async () => {
    try {
      await axios.put(`/api/prophets/${editingNode.id}`, editData, { headers: { 'x-auth-token': token } });
      setEditOpen(false);
      loadChain();
    } catch (err) { alert('Update failed'); }
  };

  // ─── D3 Vertical Tree Drawing (using filteredChain) ───
  const drawTree = useCallback(() => {
    const svg = d3.select(svgRef.current);
    svg.selectAll('*').remove();

    if (filteredChain.length === 0) return;

    // Build linear hierarchy: each node's child is the next node (if any)
    const nodes = filteredChain.map((n, i) => ({
      ...n,
      children: i < filteredChain.length - 1 ? [filteredChain[i + 1]] : [],
    }));
    const root = d3.hierarchy(nodes[0]);

    const boxW = 220;
    const boxH = 150;
    const nodeW = 280;   // horizontal space
    const nodeH = 200;   // vertical space
    const padding = 200;

    const treeLayout = d3.tree().nodeSize([nodeW, nodeH]);
    treeLayout(root);

    const descendants = root.descendants();
    const links = root.links();

    const minX = d3.min(descendants, d => d.x) - boxW / 2;
    const maxX = d3.max(descendants, d => d.x) + boxW / 2;
    const minY = d3.min(descendants, d => d.y) - boxH / 2;
    const maxY = d3.max(descendants, d => d.y) + boxH / 2;

    const width = maxX - minX + padding * 2;
    const height = maxY - minY + padding * 2;

    svg.attr('width', width).attr('height', height).attr('viewBox', `0 0 ${width} ${height}`);

    // Gradient for links
    const defs = svg.append('defs');
    const gradient = defs.append('linearGradient')
      .attr('id', 'linkGradient2')
      .attr('x1', '0%').attr('y1', '0%')
      .attr('x2', '0%').attr('y2', '100%');
    gradient.append('stop').attr('offset', '0%').attr('stop-color', '#2E7D32');
    gradient.append('stop').attr('offset', '50%').attr('stop-color', '#c9a84c');
    gradient.append('stop').attr('offset', '100%').attr('stop-color', '#2E7D32');

    const g = svg.append('g')
      .attr('transform', `translate(${padding - minX}, ${padding - minY})`);

    // Zoom behaviour
    const zoomBeh = d3.zoom().scaleExtent([0.1, 12]).on('zoom', (e) => {
      g.attr('transform', `translate(${e.transform.x}, ${e.transform.y}) scale(${e.transform.k})`);
    });
    svg.call(zoomBeh);
    const initTransform = d3.zoomIdentity.translate(width / 2 - (minX + maxX) / 2, height / 2 - (minY + maxY) / 2).scale(1);
    svg.call(zoomBeh.transform, initTransform);
    zoomRef.current = zoomBeh;

    // Links
    g.selectAll('.link').data(links, d => d.target.data.id)
      .join('path')
      .attr('fill', 'none')
      .attr('stroke', 'url(#linkGradient2)')
      .attr('stroke-width', 2.5)
      .attr('d', d => {
        const sx = d.source.x;
        const sy = d.source.y + boxH / 2;
        const tx = d.target.x;
        const ty = d.target.y - boxH / 2;
        const my = (sy + ty) / 2;
        return `M${sx},${sy} L${sx},${my} L${tx},${my} L${tx},${ty}`;
      });

    // Nodes
    const nodeGroup = g.selectAll('.node').data(descendants, d => d.data.id)
      .join('g')
      .attr('class', 'node')
      .attr('transform', d => `translate(${d.x - boxW / 2}, ${d.y - boxH / 2})`);

    // Card background
    nodeGroup.append('rect')
      .attr('width', boxW).attr('height', boxH)
      .attr('rx', 12).attr('ry', 12)
      .attr('fill', '#ffffffcc')
      .attr('stroke', '#2E7D32')
      .attr('stroke-width', 2.5);

    nodeGroup.append('rect')
      .attr('width', boxW).attr('height', 6).attr('rx', 3)
      .attr('fill', '#2E7D32');

    // Content
    nodeGroup.append('foreignObject')
      .attr('width', boxW - 20).attr('height', boxH - 50)
      .attr('x', 10).attr('y', 10)
      .append('xhtml:div')
      .style('width', '100%').style('height', '100%')
      .style('display', 'flex')
      .style('flex-direction', 'column')
      .style('align-items', 'center')
      .style('justify-content', 'center')
      .style('text-align', 'center')
      .style('font-size', '12px')
      .html(d => {
        const name = d.data.name;
        const father = getFatherName(d.data);
        const fatherLine = father ? `<br/><span style="font-size:10px;color:#1565C0;">بن ${father}</span>` : '';
        const info = d.data.info ? `<br/><span style="font-size:10px;color:#777;">${d.data.info}</span>` : '';
        return `<b>${name}</b>${fatherLine}<br/><span style="font-size:10px;color:#555;">پشت: ${d.data.generation_number}</span>${info}`;
      });

    // Admin buttons
    if (isAdmin) {
      nodeGroup.each(function(d) {
        const gNode = d3.select(this);
        const btnY = boxH - 28;

        // Add next button
        gNode.append('g')
          .attr('transform', `translate(${boxW - 36}, ${btnY})`)
          .attr('cursor', 'pointer')
          .on('click', (event) => { event.stopPropagation(); handleAddAfter(d.data); })
          .append('rect')
          .attr('width', 26).attr('height', 18).attr('rx', 8)
          .attr('fill', '#fff').attr('stroke', '#2E7D32').attr('stroke-width', 1.2);
        gNode.select('g:last-child').append('text')
          .attr('x', 13).attr('y', 14).attr('text-anchor', 'middle')
          .attr('font-size', '12px').attr('font-weight', 'bold').attr('fill', '#2E7D32').text('+');

        // Edit button
        gNode.append('g')
          .attr('transform', `translate(${boxW - 68}, ${btnY})`)
          .attr('cursor', 'pointer')
          .on('click', (event) => { event.stopPropagation(); handleEdit(d.data); })
          .append('rect')
          .attr('width', 26).attr('height', 18).attr('rx', 8)
          .attr('fill', '#fff').attr('stroke', '#1565C0').attr('stroke-width', 1.2);
        gNode.select('g:last-child').append('text')
          .attr('x', 13).attr('y', 14).attr('text-anchor', 'middle')
          .attr('font-size', '12px').attr('font-weight', 'bold').attr('fill', '#1565C0').text('✎');

        // Delete button
        gNode.append('g')
          .attr('transform', `translate(${boxW - 100}, ${btnY})`)
          .attr('cursor', 'pointer')
          .on('click', (event) => { event.stopPropagation(); handleDelete(d.data); })
          .append('rect')
          .attr('width', 26).attr('height', 18).attr('rx', 8)
          .attr('fill', '#fff').attr('stroke', '#C2185B').attr('stroke-width', 1.2);
        gNode.select('g:last-child').append('text')
          .attr('x', 13).attr('y', 14).attr('text-anchor', 'middle')
          .attr('font-size', '12px').attr('font-weight', 'bold').attr('fill', '#C2185B').text('✕');
      });
    }
  }, [filteredChain, isAdmin, getFatherName, handleAddAfter, handleEdit, handleDelete]);

  useEffect(() => {
    if (filteredChain.length > 0) drawTree();
    else d3.select(svgRef.current).selectAll('*').remove();
  }, [filteredChain, drawTree]);

  // Zoom controls
  const zoomIn = () => { if (zoomRef.current) d3.select(svgRef.current).transition().duration(300).call(zoomRef.current.scaleBy, 1.5); };
  const zoomOut = () => { if (zoomRef.current) d3.select(svgRef.current).transition().duration(300).call(zoomRef.current.scaleBy, 0.7); };
  const zoomReset = () => { if (zoomRef.current) d3.select(svgRef.current).transition().duration(300).call(zoomRef.current.transform, d3.zoomIdentity); };

  if (loading) return <Typography sx={{ textAlign: 'center', mt: 4 }}>Loading...</Typography>;

  return (
    <div style={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column' }}>
      <Typography variant="h5" align="center" sx={{ mt: 2, mb: 1, color: '#2E7D32', fontWeight: 'bold' }}>
        سلسلہ: حضرت آدم (ع) تا حضرت محمد مصطفیٰ ﷺ
      </Typography>

      {/* Generation Filter */}
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: 2, mb: 1, px: 2 }}>
        <TextField
          size="small"
          label="شروع کریں پشت نمبر"
          type="number"
          value={startGen}
          onChange={(e) => setStartGen(e.target.value)}
          sx={{ width: 160 }}
          helperText="مثلاً 78 لکھ کر Enter کریں"
          onKeyDown={(e) => { if (e.key === 'Enter') setStartGen(e.target.value); }}
        />
        <Button variant="outlined" size="small" onClick={() => setStartGen('')}>سب دکھائیں</Button>
      </Box>

      {filteredChain.length === 0 && !loading && (
        <Typography sx={{ textAlign: 'center', mt: 4 }}>
          {startGen ? 'اس پشت کے بعد کوئی ریکارڈ نہیں' : 'کوئی اندراج نہیں۔'}
        </Typography>
      )}

      <div ref={containerRef} className="tree-bg" style={{ flex: 1, overflow: 'auto', position: 'relative' }}>
        <svg ref={svgRef} style={{ display: 'block', width: '100%', height: '100%' }} />
      </div>

      <div className="control-bar">
        <button onClick={zoomOut} title="Zoom Out"><ZoomOutIcon fontSize="inherit" /></button>
        <button onClick={zoomReset} title="Reset Zoom"><CenterFocusStrongIcon fontSize="inherit" /></button>
        <button onClick={zoomIn} title="Zoom In"><ZoomInIcon fontSize="inherit" /></button>
        {isAdmin && filteredChain.length > 0 && (
          <button onClick={() => handleAddAfter(filteredChain[filteredChain.length - 1])} title="Add Last">+ Add</button>
        )}
      </div>

      {/* Add Dialog */}
      <Dialog open={open} onClose={() => setOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle sx={{ bgcolor: '#2E7D32', color: 'white' }}>نئی شخصیت شامل کریں</DialogTitle>
        <DialogContent>
          <TextField fullWidth label="نام *" margin="normal" value={newData.name} onChange={e => setNewData({ ...newData, name: e.target.value })} />
          <TextField fullWidth label="پشت نمبر *" type="number" margin="normal" value={newData.generation_number} onChange={e => setNewData({ ...newData, generation_number: e.target.value })} />
          <TextField fullWidth label="معلومات" margin="normal" value={newData.info} onChange={e => setNewData({ ...newData, info: e.target.value })} />
          <TextField fullWidth label="والد کا ID (اختیاری)" margin="normal" value={newData.parent_id} onChange={e => setNewData({ ...newData, parent_id: e.target.value })} />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpen(false)}>منسوخ</Button>
          <Button variant="contained" onClick={handleAddSubmit}>شامل کریں</Button>
        </DialogActions>
      </Dialog>

      {/* Edit Dialog */}
      <Dialog open={editOpen} onClose={() => setEditOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle sx={{ bgcolor: '#1565C0', color: 'white' }}>ترمیم کریں</DialogTitle>
        <DialogContent>
          <TextField fullWidth label="نام *" margin="normal" value={editData.name} onChange={e => setEditData({ ...editData, name: e.target.value })} />
          <TextField fullWidth label="پشت نمبر *" type="number" margin="normal" value={editData.generation_number} onChange={e => setEditData({ ...editData, generation_number: e.target.value })} />
          <TextField fullWidth label="معلومات" margin="normal" value={editData.info} onChange={e => setEditData({ ...editData, info: e.target.value })} />
          <TextField fullWidth label="والد کا ID" margin="normal" value={editData.parent_id} onChange={e => setEditData({ ...editData, parent_id: e.target.value })} />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setEditOpen(false)}>منسوخ</Button>
          <Button variant="contained" onClick={handleEditSubmit}>محفوظ کریں</Button>
        </DialogActions>
      </Dialog>
    </div>
  );
}

export default AdamToMuhammad;
